declare(strict_types=1);require __DIR__.'/bootstrap.php';require_once dirname(__DIR__,3).'/config/bootstrap.php';
$msg='';$err='';$file=beyond_private_root().'/config/live.php';$cfg=beyond_live_config();
if (empty($_SESSION['verse_generator_csrf'])) {
  $_SESSION['verse_generator_csrf'] = bin2hex(random_bytes(32));
}
function setpath(array &$a,array $parts,$value):void{$r=&$a;foreach($parts as $i=>$p){if($i===count($parts)-1){$r[$p]=$value;return;}if(!isset($r[$p])||!is_array($r[$p]))$r[$p]=[];$r=&$r[$p];}}
if($_SERVER['REQUEST_METHOD']==='POST'){
 if(!Auth::verifyCsrf($_POST['csrf']??'')){$err='Invalid security token.';}else try{
  $provider=in_array($_POST['provider']??'', ['openai','elevenlabs','azure'],true)?$_POST['provider']:'elevenlabs';setpath($cfg,['voice','provider'],$provider);
  foreach(['openai','elevenlabs','azure'] as $p){$key=trim((string)($_POST[$p.'_api_key']??''));if($key!=='')setpath($cfg,['narration',$p,'api_key'],$key);}
  $elevenLabsKey=trim((string)($_POST['elevenlabs_api_key']??''));
  if($elevenLabsKey!=='')setpath($cfg,['voice','api_key'],$elevenLabsKey);
  setpath($cfg,['narration','openai','model'],trim((string)($_POST['openai_model']??'gpt-4o-mini-tts')));
  setpath($cfg,['narration','elevenlabs','model'],trim((string)($_POST['elevenlabs_model']??'eleven_v3')));
  setpath($cfg,['voice','model_id'],trim((string)($_POST['elevenlabs_model']??'eleven_v3')));
  setpath($cfg,['narration','azure','region'],trim((string)($_POST['azure_region']??'')));
  setpath($cfg,['voice','openai_voice'],trim((string)($_POST['openai_voice']??'coral')));
  foreach(['en-US','fr-FR','fr-CA','es-ES','ht-HT','en-JM'] as $loc){$v=trim((string)($_POST['voice_'.str_replace('-','_',$loc)]??''));if($v!==''){setpath($cfg,['narration','elevenlabs','voices',$loc],$v);setpath($cfg,['voice','voices',$loc],$v);}}
  $php="<?php\ndeclare(strict_types=1);\n/* Protected live configuration. Keep beside public_html. */\nreturn ".var_export($cfg,true).";\n";$tmp=$file.'.tmp';if(file_put_contents($tmp,$php,LOCK_EX)===false||!rename($tmp,$file))throw new RuntimeException('Could not update protected configuration.');@chmod($file,0600);$msg='Premium voice settings saved.';
 }catch(Throwable $e){$err=$e->getMessage();}
}
