<script>
(()=>{const b=document.getElementById('testElevenLabs'),s=document.getElementById('elevenTestStatus');if(!b)return;b.addEventListener('click',async()=>{b.disabled=true;s.textContent='Testing…';try{const r=await fetch('/beyond-id/admin/api/elevenlabs-test.php',{method:'POST',headers:{'X-CSRF-Token':'<?=DailyStudio::esc((string)($_SESSION['verse_generator_csrf']??''))?>'}});const d=await r.json();if(!r.ok)throw new Error(d.error||'Connection failed.');s.textContent=d.message;const voices=Array.isArray(d.voices)?d.voices:[];if(voices.length){document.querySelectorAll('input[placeholder="ElevenLabs voice ID"]').forEach(input=>{if(!input.value)input.value=voices[0].id;});s.textContent+=' Blank Voice ID fields were filled with '+voices[0].name+'. Save settings to keep them.';}}catch(e){s.textContent=e.message||'Connection failed.';}finally{b.disabled=false;}});})();
</script>
